import axios from 'axios';
import mockProducts from '../data/mockProducts';

// ─── Toggle this to false when your backend is ready ───
const USE_MOCK = true;

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: { 'Content-Type': 'application/json' },
});

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

// ─── Mock helpers ───────────────────────────────────────
const mockDelay = (data, ms = 300) =>
  new Promise((resolve) =>
    setTimeout(() => resolve({ data }), ms)
  );

const applyMockFilters = (params = {}) => {
  let results = [...mockProducts];

  if (params.category)
    results = results.filter((p) =>
      p.category.toLowerCase() === params.category.toLowerCase()
    );

  if (params.subcategory)
    results = results.filter((p) =>
      p.subcategory.toLowerCase() === params.subcategory.toLowerCase()
    );

  if (params.brand)
    results = results.filter((p) =>
      p.brand.toLowerCase().includes(params.brand.toLowerCase())
    );

  if (params.search)
    results = results.filter((p) =>
      p.name.toLowerCase().includes(params.search.toLowerCase())
    );

  if (params.featured)
    results = results.filter((p) => p.variants[0].inventory_quantity > 0);

  if (params.limit)
    results = results.slice(0, Number(params.limit));

  return results;
};

// ─── API exports ────────────────────────────────────────
export const authAPI = {
  sendOtp: (phone) => api.post('/api/auth/send-otp/', { phone }),
  verifyOtp: (phone, otp) => api.post('/api/auth/verify-otp/', { phone, otp }),
  me: () => api.get('/api/auth/me/'),
};

export const productAPI = {
  list: (params) =>
    USE_MOCK
      ? mockDelay(applyMockFilters(params))
      : api.get('/api/products/', { params }),

  detail: (slug) =>
    USE_MOCK
      ? mockDelay(mockProducts.find((p) => p.slug === slug) || null)
      : api.get(`/api/products/${slug}/`),

  categories: () =>
    USE_MOCK
      ? mockDelay([...new Set(mockProducts.map((p) => p.category))])
      : api.get('/api/categories/'),
};

export const cartAPI = {
  reserve: (data) => api.post('/api/inventory/reserve/', data),
  sync: (items) => api.post('/api/cart/sync/', { items }),
};

export const orderAPI = {
  create: (data) => api.post('/api/orders/', data),
  list: () => api.get('/api/orders/'),
  detail: (id) => api.get(`/api/orders/${id}/`),
  track: (id) => api.get(`/api/orders/${id}/track/`),
};

export const paymentAPI = {
  createOrder: (data) => api.post('/api/payments/create-order/', data),
  verify: (data) => api.post('/api/payments/verify/', data),
};

export const adminAPI = {
  dashboard: () => api.get('/api/admin/dashboard/'),
  products: (params) => api.get('/api/admin/products/', { params }),
  updateProduct: (id, data) => api.patch(`/api/admin/products/${id}/`, data),
  orders: (params) => api.get('/api/admin/orders/', { params }),
  updateOrderStatus: (id, status) => api.patch(`/api/admin/orders/${id}/`, { status }),
  tickets: () => api.get('/api/admin/tickets/'),
};

export default api;
